const prims = ['string','number','boolean','Date','UUID','decimal','date','uuid'];
const attrs = attributes || [];
const types = attrs.filter(function (a) { return !a.reference; }).map(function (a) { return a.type; }).filter(function (t) { return prims.indexOf(t) === -1; });
nonPrimitives = Array.from(new Set(types));

const primMap = { string: 'z.string()', number: 'z.number()', boolean: 'z.boolean()', date: 'z.date()', uuid: 'z.string().uuid()', decimal: 'z.number()' };
// Date/UUID legacy-cased fall through to the type's pascal-cased schema reference; same as primitive entries on the legacy-cased keys.
primMap['Date'] = 'z.date()';
primMap['UUID'] = 'z.string().uuid()';
function zodFor(a) {
  let base = primMap[a.type] || (pascalCase(a.type) + 'Schema');
  if (a.multiValue) { base += '.array()'; }
  if (!a.required) { base += '.optional()'; }
  if (a.description) { base += '.describe("' + a.description + '")'; }
  return base;
}

attrSpecs = (attributes || []).map(function (a) {
  return { camel: camelCase(a.name), zodType: zodFor(a) };
});

import { z } from 'zod'
{{#each nonPrimitives}}
import { {{pascalCase this}}Schema } from './{{pascalCase this}}Schema';
{{/each}}
